var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"후우...... 배식 한 번 받는 데 무슨 몸싸움까지 벌어지냐.","JPN":"ふう……配膳一回のためになんでケンカまでしなきゃなんないんだ。","ENG":"Ugh... Do we have to bicker every time we get in line?","TWN":"哎……分個餐何必推來推去的。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"할아버지, 이거 잡수십쇼.","JPN":"じいさん、これでもどうぞ。","ENG":"Hey, gramps. You can have this.","TWN":"老爺爺，你吃吧。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REFUGEE_NPC_OLD_NULL","text":{"KOREA":"아니, 청년도 오래 기다렸을 텐데......","JPN":"いや、君もだいぶ待っていただろうに……","ENG":"Oh, but I'm sure you've waited a while too, young man...","TWN":"不，你不是也等了很長時間嗎……"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"다이어트 중이라서요.","JPN":"ダイエット中なんです。","ENG":"I'm on a diet.","TWN":"我在減肥。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......그러면서 시리얼 먹는 건 불만이야?","JPN":"……そんなやつがシリアルにはあんなにぶーぶー言って。","ENG":"And you're complaining about cereal?","TWN":"……那你還對吃麥片憤憤不平？"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"어, 내가 제일 좋아하는 음식이 시리얼이거든.","JPN":"まあ、俺が一番好きな食べ物はシリアルだからな。","ENG":"It just so happens that cereal is my favorite food.","TWN":"唔，我最愛吃的食品就是麥片。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"급식은 양보해도 시리얼 뺏어가는 녀석에겐 총알을 박아주지.","JPN":"炊き出しは譲っても、シリアルだけは絶対に譲らないぞ。","ENG":"I'll pass on soup kitchen food any day, but the fool who takes my cereal away will get a bullet in their head.","TWN":"我可以忍讓配餐，但饒不了有人搶走我的麥片。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"어떻게 몇 년이 지나도 전공서는 바뀌는 게 없냐......","JPN":"何年も経ったのに、大学のテキストってまったく変わんないんだな……","ENG":"They never update these textbooks, do they?","TWN":"過了這麼多年，教科書一點變化也沒有……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"자, 교수가 제정신이면 이건 문제로 꼭 나온다. 밑줄 치고 공부해 둬.","JPN":"ほら、教授がまともな人ならこれは絶対に試験に出るから。ちゃんとチェックして覚えておけ。","ENG":"Unless your professor is completely nuts, this is definitely going to be in the test. Highlight it.","TWN":"注意，如果是發神經的教授，肯定會出這道題，標紅後記得複習。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REFUGEE_NPC_GUY_NULL","text":{"KOREA":"아, 고맙습니다. 형.","JPN":"ありがとうございます。","ENG":"Oh, thank you.","TWN":"啊，謝謝，哥。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"고마우면 말로 하지 말고 폐기할 예정인 우유나 좀 줘.","JPN":"お礼の言葉はいいから、廃棄予定の牛乳でもあればくれよ。","ENG":"If you're so grateful, why don't you hook me up with some leftover milk before it expires?","TWN":"別光嘴上說，請我喝點報廢的牛奶吧。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......대학생이었어? 예전에?","JPN":"……昔は大学に通ってたの？","ENG":"You went to college?","TWN":"……你以前是大學生？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그랬던 적이 있었던 것 같기도 하고, 없었던 것 같기도 하고.","JPN":"そうだったような、違かったような気もするな。","ENG":"I think so? Maybe not.","TWN":"好像是，又好像不是。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그럼 뭐 앞으로 오빠라고 불러야 되나?","JPN":"なんだ、これからは兄さんって呼べばいいのか？","ENG":"Dang... I didn't know you were older than me.","TWN":"那我以後要叫你哥哥嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"징그럽게 헛소리는. 내 여동생은 너보다 훨씬 귀엽다고.","JPN":"やめろよ気味悪い。俺の妹はお前よりずっと可愛いぞ。","ENG":"Yeah, don't expect me to baby you like I did with my sister.","TWN":"怪肉麻的，我妹妹比妳長得漂亮多了。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"뭐, 동료로는 너도 나쁘지 않지만.","JPN":"ま、同僚としてはお前も悪くないけど。","ENG":"I guess you make an okay fellow though.","TWN":"不過，妳作為同伴還算不錯。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};